-- ============================================================
-- HELPERS
-- ============================================================
local function tw(obj, t, props)
    return TweenService:Create(obj, TweenInfo.new(t, Enum.EasingStyle.Quart), props)
end
local function corner(p, r)
    local c = Instance.new("UICorner", p)
    c.CornerRadius = UDim.new(0, r or 8)
    return c
end
local function mkStroke(p, col, thick, trans)
    local s = Instance.new("UIStroke", p)
    s.Color = col or ACCENT
    s.Thickness = thick or 1.5
    s.Transparency = trans or 0
    return s
end
local function lbl(parent, text, pos, size, color, sz, bold, align, wrap)
    local l = Instance.new("TextLabel", parent)
    l.Text                   = text
    l.Position               = pos
    l.Size                   = size
    l.BackgroundTransparency = 1
    l.TextColor3             = color or TEXT
    l.Font                   = bold and Enum.Font.GothamBold or Enum.Font.Gotham
    l.TextSize               = sz or 12
    l.TextXAlignment         = align or Enum.TextXAlignment.Left
    l.TextWrapped            = wrap or false
    return l
end

