local stageList = {}
for i, name in ipairs({"Connecting to server…","Verifying license…","Checking HWID…","Finalizing access…"}) do
    local row = Instance.new("Frame", stageFrame)
    row.Size=UDim2.new(0.9,0,0,22) row.Position=UDim2.new(0.05,0,0,28+(i-1)*24)
    row.BackgroundTransparency=1
    local dot=Instance.new("TextLabel",row)
    dot.Size=UDim2.new(0,16,1,0) dot.BackgroundTransparency=1 dot.Text="○"
    dot.TextColor3=Color3.fromRGB(60,80,120) dot.Font=Enum.Font.GothamBold
    dot.TextSize=13 dot.TextXAlignment=Enum.TextXAlignment.Center
    local sl=Instance.new("TextLabel",row)
    sl.Size=UDim2.new(1,-20,1,0) sl.Position=UDim2.new(0,20,0,0)
    sl.BackgroundTransparency=1 sl.Text=name sl.TextColor3=Color3.fromRGB(60,80,120)
    sl.Font=Enum.Font.Gotham sl.TextSize=12 sl.TextXAlignment=Enum.TextXAlignment.Left
    stageList[i]={dot=dot,lbl=sl}
end

local function runStageAnimation(onDone)
    stageFrame.Visible=true
    for _,s in ipairs(stageList) do
        s.dot.Text="○" s.dot.TextColor3=Color3.fromRGB(60,80,120)
        s.dot.TextTransparency=0 s.lbl.TextColor3=Color3.fromRGB(60,80,120)
    end
    task.spawn(function()
        for i,s in ipairs(stageList) do
            if i>1 then
                stageList[i-1].dot.Text="●" stageList[i-1].dot.TextColor3=SUCCESS
                stageList[i-1].lbl.TextColor3=SUCCESS
            end
            s.dot.Text="●" s.dot.TextColor3=ACCENT s.lbl.TextColor3=TEXT
            local e=0
            while e<0.55 do
                if s.dot and s.dot.Parent then s.dot.TextTransparency=math.abs(math.sin(e*math.pi/0.28)) end
                e+=0.05 task.wait(0.05)
            end
            s.dot.TextTransparency=0
        end
        stageList[#stageList].dot.Text="●" stageList[#stageList].dot.TextColor3=SUCCESS
        stageList[#stageList].lbl.TextColor3=SUCCESS
        task.wait(0.5)
        tw(stageFrame,0.35,{BackgroundTransparency=1}):Play() task.wait(0.4)
        stageFrame.Visible=false stageFrame.BackgroundTransparency=0
        if onDone then onDone() end
    end)
end

