        { user = "xXTinyLagXx",         text = "no way this is this smooth"            },
        { user = "RobloxSnack",         text = "this is actually kinda addictive lol"  },
        { user = "LilChaosDev",         text = "everything just feels right here"      },
        { user = "xXRandomProXx",       text = "ok yeah this is valid af"              },
    }

    for _, t in ipairs(testimonials) do
        local row=Instance.new("Frame",revScroll)
        row.Size=UDim2.new(1,0,0,26) row.BackgroundColor3=INPUT corner(row,5)
        local uLbl=Instance.new("TextLabel",row) uLbl.Size=UDim2.new(0,120,1,0) uLbl.Position=UDim2.new(0,6,0,0)
        uLbl.BackgroundTransparency=1 uLbl.Text=t.user uLbl.TextColor3=ACCENT uLbl.Font=Enum.Font.GothamBold uLbl.TextSize=10 uLbl.TextXAlignment=Enum.TextXAlignment.Left
        local tLbl=Instance.new("TextLabel",row) tLbl.Size=UDim2.new(1,-130,1,0) tLbl.Position=UDim2.new(0,126,0,0)
        tLbl.BackgroundTransparency=1 tLbl.Text='"'..t.text..'"' tLbl.TextColor3=DIM tLbl.Font=Enum.Font.Gotham tLbl.TextSize=10 tLbl.TextXAlignment=Enum.TextXAlignment.Left
    end

    -- BUY BUTTON
    local buyBtn=Instance.new("TextButton",shopCard)
    buyBtn.Size=UDim2.new(1,-24,0,44) buyBtn.Position=UDim2.new(0,12,0,revY+130)
    buyBtn.BackgroundColor3=ACCENT buyBtn.Text="" buyBtn.AutoButtonColor=false
    corner(buyBtn,10) mkStroke(buyBtn,ACCENT2,1,0.3)

    local bTxt = lbl(buyBtn,"🛒  Get Lifetime Now! ",UDim2.new(0,0,0,0),UDim2.new(1,0,1,0),TEXT,14,true,Enum.TextXAlignment.Center)

    buyBtn.MouseButton1Click:Connect(function()
        pcall(function() setclipboard(SHOP_LINK) end)
        bTxt.Text = "✅ Link Copied!"
        task.delay(2.5, function()
            if bTxt and bTxt.Parent then bTxt.Text = "🛒  Get Lifetime — Copy Shop Link" end
        end)
    end)

    local function closeShop()
        shopOpen = false
        tw(shopCard,0.3,{Position=UDim2.new(0.5,420,0.5,0)}):Play()
        task.wait(0.35)
        if sg and sg.Parent then sg:Destroy() end
        shopGuiRef = nil
    end
    closeBtn.MouseButton1Click:Connect(closeShop)

    shopCard.Size = UDim2.new(0, 370, 0, revY + 200)
end

