shopBtnContainer.Size             = UDim2.new(0, 126, 0, 30)
shopBtnContainer.Position         = UDim2.new(0, 10, 1, -40)
shopBtnContainer.BackgroundTransparency = 1

shopTriggerBtn = Instance.new("TextButton", shopBtnContainer)
