shopTriggerBtn.BackgroundColor3 = Color3.fromRGB(12, 20, 40)
shopTriggerBtn.Text             = "🛒  Shop"
shopTriggerBtn.TextColor3       = ACCENT
shopTriggerBtn.Font             = Enum.Font.GothamBold
shopTriggerBtn.TextSize         = 12
shopTriggerBtn.AutoButtonColor  = false
corner(shopTriggerBtn, 8)
mkStroke(shopTriggerBtn, ACCENT, 1, 0.4)

local shopDismissBtn = Instance.new("TextButton", shopBtnContainer)
shopDismissBtn.Size             = UDim2.new(0, 30, 0, 30)
shopDismissBtn.Position         = UDim2.new(0, 96, 0, 0)
shopDismissBtn.BackgroundColor3 = Color3.fromRGB(40, 15, 15)
shopDismissBtn.Text             = "×"
shopDismissBtn.TextColor3       = Color3.fromRGB(255, 80, 80)
shopDismissBtn.Font             = Enum.Font.GothamBold
