shopDismissBtn.AutoButtonColor  = false
corner(shopDismissBtn, 8)
mkStroke(shopDismissBtn, Color3.fromRGB(255, 80, 80), 1, 0.5)

shopTriggerBtn.MouseButton1Click:Connect(function()
    if shopOpen then
        local existing = pgui:FindFirstChild("EurokeShop")
        if existing then existing:Destroy() end
        shopOpen = false
    else
        shopOpen = true
        buildShop()
    end
end)

shopDismissBtn.MouseButton1Click:Connect(function()
    -- Close shop panel if open
    shopOpen = false
    shopGuiRef = nil
    for _, v in ipairs(pgui:GetChildren()) do
        if v.Name == "EurokeShop" then v:Destroy() end
    end
    -- Hide the button row from screen
    local container = shopDismissBtn.Parent
    if container and container.Parent then
        container:Destroy()
    end
end)

-- ============================================================
-- MASK KEY HELPER
-- ============================================================
local function maskKey(key)
    if not key or #key < 4 then return "****" end
    return string.rep("*", math.max(0, #key-4)) .. key:sub(-4)
end

-- ============================================================
-- CALLBACKS
-- ============================================================
Arqel.Callbacks.OnSuccess = function(key)
    if hasVerified then return end
    hasVerified = true

    runStageAnimation(function()
        showSuccessScreen(maskKey(key))

        task.wait(2)

        -- CLOSE ALL UI AFTER SUCCESS
        if stageGui then stageGui:Destroy() end
        if successGui then successGui:Destroy() end
        if screen then screen:Destroy() end

        local shop = pgui:FindFirstChild("EurokeShop")
        if shop then shop:Destroy() end

        Arqel:LaunchJunkie({
            Service = "Euroke",
            Identifier = "1067460",
            Provider = "Euroke"
        })
    end)
end

Arqel.Callbacks.OnFail = function()
    tw(sp_stroke, 0.1, {Color=Color3.fromRGB(255,80,100)}):Play()
    task.delay(1.2, function()
        if sp_stroke and sp_stroke.Parent then tw(sp_stroke,0.4,{Color=ACCENT}):Play() end
    end)
end

Arqel.Callbacks.OnClose = function()
    if screen and screen.Parent then screen:Destroy() end
    local existing = pgui:FindFirstChild("EurokeShop")
    if existing then existing:Destroy() end
end


-- ============================================================
-- LAUNCH KEY SYSTEM
-- ============================================================
Arqel:LaunchJunkie({
    Service    = "Euroke",
    Identifier = "1067460",
    Provider   = "Euroke",
    Messages = {
        Welcome    = "Welcome to Euroke Max",
        StatusIdle = "Waiting for key...",
        Checking   = "Verifying key...",
        Success    = "Access Granted ✔",
        Failed     = "Invalid Key ✖",
        Expired    = "Key Expired",
    },
    UI = {
        Placeholder = "Enter your key here...",
        ButtonText  = "Unlock",
        GetKeyText  = "Get Key",
    }
})

print("Euroke MAX key system ready!")

